import os
from flask import Flask, request, jsonify
from funct import create_token, verify_token_decorator

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'your_super_secret_key_here') # Use a strong, random key in production


# Simple user store (for demonstration purposes)
# In a real application, you'd use a database
USERS = {
    'user1': 'pass1',
    'admin': 'adminpass'
}

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username', None)
    password = request.json.get('password', None)

    if not username or not password:
        return jsonify({"msg": "Missing username or password"}), 400

    if USERS.get(username) == password:
        token = create_token(username, app.config['SECRET_KEY'])
        return jsonify(token=token), 200
    else:
        return jsonify({"msg": "Bad username or password"}), 401

@app.route('/protected', methods=['GET'])
@verify_token_decorator(app.config['SECRET_KEY'])
def protected_route():
    # The identity of the user is now available via request.user
    return jsonify({"msg": f"Hello {request.user}! You accessed a protected route."}), 200

@app.route('/admin_only', methods=['GET'])
@verify_token_decorator(app.config['SECRET_KEY'])
def admin_only_route():
    # In a real app, you'd also check roles/permissions
    if request.user != 'admin':
        return jsonify({"msg": "Admin access required"}), 403
    return jsonify({"msg": f"Welcome, admin {request.user}! This is an admin-only area."}), 200


